import React, { useState, useEffect } from 'react';
import { UserData, SystemConfig } from '../App';
import { useLanguage } from './LanguageContext';

interface LoginScreenProps {
  onLoginSuccess: (username: string, role: 'ADMIN' | 'USER' | 'LEADER') => void;
  users: UserData[];
  systemConfig: SystemConfig;
}

const LoginScreen: React.FC<LoginScreenProps> = ({ onLoginSuccess, users, systemConfig }) => {
  const [username, setUsername] = useState<string>('');
  const [password, setPassword] = useState<string>('');
  const [error, setError] = useState<string>('');
  const { t } = useLanguage();

  // IP Check State
  const [clientIP, setClientIP] = useState<string | null>(null);
  const [isIpAllowed, setIsIpAllowed] = useState<boolean>(true);
  const [loadingIp, setLoadingIp] = useState<boolean>(false);

  // Scheduled Maintenance Check
  const now = new Date();
  const currentISO = new Date(now.getTime() - (now.getTimezoneOffset() * 60000)).toISOString().slice(0, 16);
  const isScheduledMaintenance = systemConfig.maintenanceStart && systemConfig.maintenanceEnd && 
                                 currentISO >= systemConfig.maintenanceStart && 
                                 currentISO <= systemConfig.maintenanceEnd;
  const isMaintenance = systemConfig.maintenanceMode || isScheduledMaintenance;

  useEffect(() => {
      // Fetch Client IP if check is enabled
      if (systemConfig.ipCheckEnabled) {
          setLoadingIp(true);
          fetch('https://api.ipify.org?format=json')
              .then(res => res.json())
              .then(data => {
                  setClientIP(data.ip);
                  checkIpAgainstWhitelist(data.ip);
              })
              .catch(err => {
                  console.error('IP fetch failed', err);
                  setClientIP('Unknown');
                  setIsIpAllowed(true); 
              })
              .finally(() => setLoadingIp(false));
      } else {
          setIsIpAllowed(true);
      }
  }, [systemConfig.ipCheckEnabled, systemConfig.allowedIPs]);

  const checkIpAgainstWhitelist = (ip: string) => {
      if (!systemConfig.allowedIPs || systemConfig.allowedIPs.length === 0) {
          setIsIpAllowed(true); // Empty list = allow all
          return;
      }

      const allowed = systemConfig.allowedIPs.some(pattern => {
          if (pattern.includes('*')) {
              const prefix = pattern.split('*')[0];
              return ip.startsWith(prefix);
          }
          return pattern === ip;
      });
      setIsIpAllowed(allowed);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const normalizedInputUsername = username.trim().toUpperCase();

    // Check IP First
    if (systemConfig.ipCheckEnabled && !isIpAllowed) {
        const foundUser = users.find(u => u.username.toUpperCase() === normalizedInputUsername);

        if (foundUser && foundUser.password === password) {
             if (foundUser.role === 'ADMIN') {
                 onLoginSuccess(foundUser.username, foundUser.role);
                 return;
             }
        }
        setError(t('ip_blocked_title')); 
        return;
    }

    const foundUser = users.find(u => u.username.toUpperCase() === normalizedInputUsername);

    if (foundUser && foundUser.password === password) {
      if (isMaintenance && foundUser.role !== 'ADMIN') {
          setError(t('login_error_maint'));
      } else {
          setError('');
          onLoginSuccess(foundUser.username, foundUser.role);
      }
    } else {
      setError(t('login_error'));
    }
  };

  return (
    <div className="flex flex-col items-center w-full max-w-md mx-4">

      {/* Maintenance Banner */}
      {isMaintenance && (
          <div className="w-full mb-6 bg-yellow-900/50 border border-yellow-600 p-4 rounded-xl text-center animate-pulse">
              <h3 className="text-xl font-bold text-yellow-500 uppercase">{t('maint_active_title')}</h3>
              <p className="text-yellow-200 text-sm mt-1">{t('maint_active_desc')}</p>
              {isScheduledMaintenance && (
                  <p className="text-xs text-yellow-400 mt-2 font-mono">
                      {t('maint_scheduled_msg', { 
                          start: new Date(systemConfig.maintenanceStart!).toLocaleString(), 
                          end: new Date(systemConfig.maintenanceEnd!).toLocaleString() 
                      })}
                  </p>
              )}
          </div>
      )}

      {/* IP Block Banner */}
      {systemConfig.ipCheckEnabled && !loadingIp && !isIpAllowed && (
           <div className="w-full mb-6 bg-red-900/50 border border-red-600 p-4 rounded-xl text-center">
               <h3 className="text-xl font-bold text-red-500 uppercase">{t('ip_blocked_title')}</h3>
               <p className="text-red-200 text-sm mt-1">{t('ip_blocked_desc', { ip: clientIP || 'Unknown' })}</p>
           </div>
      )}

      <div className="w-full p-6 sm:p-8 space-y-6 sm:space-y-8 bg-gray-800 rounded-xl shadow-lg relative overflow-hidden">
        {loadingIp && (
            <div className="absolute inset-0 bg-gray-900/80 flex items-center justify-center z-50">
                <p className="text-teal-400 animate-pulse font-bold">{t('checking_ip')}</p>
            </div>
        )}

        <div className="text-center">
          <h2 className="text-3xl font-extrabold text-teal-400 mb-2">
            {t('login_title')}
          </h2>
          <p className="mt-2 text-sm text-gray-400">
            {t('login_subtitle')}
          </p>
        </div>
        <form className="mt-6 sm:mt-8 space-y-6" onSubmit={handleSubmit}>
          <div className="rounded-md shadow-sm -space-y-px">
            <div>
              <label htmlFor="username" className="sr-only">{t('username')}</label>
              <input
                id="username"
                name="username"
                type="text"
                autoComplete="username"
                required
                autoFocus
                className={`appearance-none rounded-none rounded-t-md relative block w-full px-3 py-3 border placeholder-gray-500 text-white bg-gray-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-gray-800 focus:ring-teal-500 focus:z-10 text-base sm:text-sm ${error ? 'border-red-500' : 'border-gray-600'}`}
                placeholder={t('username')}
                value={username}
                onChange={(e) => {
                  setUsername(e.target.value);
                  if (error) setError('');
                }}
              />
            </div>
            <div>
              <label htmlFor="password" className="sr-only">{t('password')}</label>
              <input
                id="password"
                name="password"
                type="password"
                autoComplete="current-password"
                required
                className={`appearance-none rounded-none rounded-b-md relative block w-full px-3 py-3 border placeholder-gray-500 text-white bg-gray-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-gray-800 focus:ring-teal-500 focus:z-10 text-base sm:text-sm ${error ? 'border-red-500' : 'border-gray-600'}`}
                placeholder={t('password')}
                value={password}
                onChange={(e) => {
                  setPassword(e.target.value);
                  if (error) setError('');
                }}
              />
            </div>
          </div>

          {error && <p className="text-sm text-red-400 text-center font-bold">{error}</p>}

          <div>
            <button
              type="submit"
              disabled={systemConfig.ipCheckEnabled && !isIpAllowed}
              className={`group relative w-full flex justify-center py-3 px-4 border border-teal-500/50 text-sm font-black rounded-md text-white transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-gray-800 focus:ring-teal-500 
                  ${systemConfig.ipCheckEnabled && !isIpAllowed 
                    ? 'bg-gray-600 cursor-not-allowed opacity-50' 
                    : 'bg-teal-600 hover:bg-teal-500 shadow-[0_0_15px_rgba(13,148,136,0.4)]'
                  }`}
            >
              {t('login_btn').toUpperCase()}
            </button>
          </div>
        </form>
      </div>

      {/* Footer Credit */}
      <div className="mt-8 text-center text-xs text-gray-500 opacity-60">
          <p>{t('created_by')}</p>
          <p className="mt-1">© 2025</p>
      </div>
    </div>
  );
};

export default LoginScreen;

import React, { useState, useRef, useEffect } from 'react';
import { TAB_CONFIG, DEFAULT_TAB_ORDER } from '../constants/uiConstants';
import { SystemConfig } from '../types/appTypes';

interface TabNavigatorProps {
  activeTab: string;
  setActiveTab: (tab: any) => void;
  hasPermission: (perm: string) => boolean;
  t: (key: any) => string;
  counts: {
    tasks: number;
    pendingRequests: number;
    erpBlockages: number;
  };
  currentUserRole?: string;
  systemConfig?: SystemConfig;
}

const ChevronIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 9l-7 7-7-7" />
    </svg>
);

const TabNavigator: React.FC<TabNavigatorProps> = ({
  activeTab,
  setActiveTab,
  hasPermission,
  t,
  counts,
  currentUserRole,
  systemConfig
}) => {
  const [isAdminMenuOpen, setIsAdminMenuOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const currentOrder = systemConfig?.tabOrder || DEFAULT_TAB_ORDER;

  // Filtrujeme položky, ktoré pôjdu do horizontálneho menu
  const mainTabs = currentOrder.filter(id => id !== 'settings' && id !== 'permissions');

  // Kontrola, či má užívateľ prístup aspoň k jednej admin časti
  const canSeeSettings = hasPermission('perm_tab_settings');
  const canSeePermissions = hasPermission('perm_tab_permissions');
  const hasAdminAccess = canSeeSettings || canSeePermissions;

  // Kontrola, či je vybraná nejaká položka z administrácie
  const isAnyAdminTabActive = activeTab === 'settings' || activeTab === 'permissions';

  // Kliknutie mimo dropdownu ho zavrie
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsAdminMenuOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleTabClick = (tabId: string) => {
      setActiveTab(tabId);
      setIsAdminMenuOpen(false);
  };

  return (
    <div className="bg-gray-800 border-t border-gray-700 shadow-sm z-30">
      <div className="max-w-7xl mx-auto w-full px-2 sm:px-4 overflow-x-auto custom-scrollbar">
        <div className="flex space-x-4 sm:space-x-6 items-center">
          {mainTabs.map(tabId => {
            const config = TAB_CONFIG.find(c => c.id === tabId);
            if (!config) return null;

            if (config.adminOnly && currentUserRole !== 'ADMIN') return null;
            if (!hasPermission(config.permission)) return null;

            const isActive = activeTab === config.id;
            const badgeValue = config.badgeKey ? counts[config.badgeKey] : 0;
            const hasBadge = badgeValue > 0;

            const activeColorClass = config.color || 'border-teal-500 text-teal-400';
            const badgeColorClass = 'bg-orange-600';

            return (
              <button
                key={config.id}
                onClick={() => handleTabClick(config.id)}
                className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${
                  isActive 
                    ? activeColorClass 
                    : `border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500 ${hasBadge ? 'text-orange-400/80' : ''}`
                }`}
              >
                {t(config.labelKey as any)}
                {hasBadge && (
                  <span className={`ml-1 sm:ml-2 text-white text-[10px] rounded-full px-1.5 sm:px-2 py-0.5 ${badgeColorClass}`}>
                    {badgeValue}
                  </span>
                )}
              </button>
            );
          })}

          {/* ADMINISTRÁCIA DROPDOWN */}
          {hasAdminAccess && (
              <div className="relative h-full" ref={dropdownRef}>
                  <button
                    onClick={() => setIsAdminMenuOpen(!isAdminMenuOpen)}
                    className={`flex items-center gap-1.5 whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors h-full ${
                        isAnyAdminTabActive 
                        ? 'border-amber-500 text-amber-400' 
                        : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'
                    }`}
                  >
                    {t('tab_administration')}
                    {counts.pendingRequests > 0 && (
                        <span className="w-2 h-2 rounded-full bg-red-500 animate-ping"></span>
                    )}
                    <ChevronIcon className={`w-3.5 h-3.5 transition-transform duration-200 ${isAdminMenuOpen ? 'rotate-180' : ''}`} />
                  </button>

                  {isAdminMenuOpen && (
                      <div className="absolute right-0 top-full mt-1 w-56 bg-gray-900 border border-gray-700 rounded-xl shadow-2xl overflow-hidden animate-fade-in py-2">
                          {canSeeSettings && (
                              <button 
                                onClick={() => handleTabClick('settings')}
                                className={`w-full text-left px-5 py-3 text-xs font-black uppercase tracking-widest transition-colors flex items-center justify-between group ${activeTab === 'settings' ? 'bg-teal-600/10 text-teal-400' : 'text-gray-400 hover:bg-gray-800 hover:text-white'}`}
                              >
                                  <span>{t('tab_settings')}</span>
                                  {counts.pendingRequests > 0 && (
                                      <span className="bg-red-500 text-white text-[9px] px-1.5 rounded-full">{counts.pendingRequests}</span>
                                  )}
                              </button>
                          )}
                          {canSeePermissions && (
                              <button 
                                onClick={() => handleTabClick('permissions')}
                                className={`w-full text-left px-5 py-3 text-xs font-black uppercase tracking-widest transition-colors ${activeTab === 'permissions' ? 'bg-amber-600/10 text-amber-400' : 'text-gray-400 hover:bg-gray-800 hover:text-white'}`}
                              >
                                  {t('tab_permissions')}
                              </button>
                          )}
                      </div>
                  )}
              </div>
          )}
        </div>
      </div>
    </div>
  );
};

