const PartSearchScreen: React.FC<PartSearchScreenProps> = (props) => {
    const { t, language, setLanguage } = useLanguage();
    const [activeTab, setActiveTab] = useState('entry');
    const [mode, setMode] = useState<'production' | 'logistics'>('production');
    const [isFullscreen, setIsFullscreen] = useState(false);

    // Form states for adding new tasks
    const [selectedPart, setSelectedPart] = useState<string | null>(null);
    const [selectedWorkplace, setSelectedWorkplace] = useState<string | null>(null);
    const [quantity, setQuantity] = useState('');
    const [quantityUnit, setQuantityUnit] = useState<'pcs' | 'boxes' | 'pallet'>('pcs');
    const [priority, setPriority] = useState<PriorityLevel>('NORMAL');
    const [logisticsRef, setLogisticsRef] = useState('');
    const [logisticsPlate, setLogisticsPlate] = useState('');
    const [logisticsOp, setLogisticsOp] = useState('');
    const [sourceSector, setSourceSector] = useState<string | null>(null);
    const [targetSector, setTargetSector] = useState<string | null>(null);

    // Fullscreen handling
    const toggleFullscreen = () => {
        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen().then(() => setIsFullscreen(true)).catch(err => console.error(err));
        } else {
            if (document.exitFullscreen) {
                document.exitFullscreen().then(() => setIsFullscreen(false)).catch(err => console.error(err));
            }
        }
    };

    // Permission check memoized for children
    const hasPermission = useCallback((permName: string) => {
        if (props.currentUserRole === 'ADMIN') return true;
        const roleObj = props.roles.find(r => r.name === props.currentUserRole);
        if (!roleObj) return false;
        return roleObj.permissions ? roleObj.permissions.includes(permName) : false;
    }, [props.roles, props.currentUserRole]);

    // Name resolution memoized for performance
    const resolveName = useCallback((username?: string | null) => {
        if (!username) return '-';
        const u = props.users.find(x => x.username === username);
        return (u?.nickname || username).toUpperCase();
    }, [props.users]);

    const resetEntry = () => {
        setSelectedPart(null);
        setSelectedWorkplace(null);
        setQuantity('');
        setQuantityUnit('pcs');
        setPriority('NORMAL');
        setLogisticsRef('');
        setLogisticsPlate('');
        setLogisticsOp('');
        setSourceSector(null);
        setTargetSector(null);
    };

    const handleAddTask = async () => {
        if (mode === 'production') {
            if (!selectedPart || !selectedWorkplace || !quantity) {
                alert(t('fill_all_fields'));
                return;
            }
            await props.onAddTask(
                selectedPart,
                selectedWorkplace,
                quantity,
                quantityUnit,
                priority,
                false,
                '',
                true
            );
            resetEntry();
        } else {
            if (!logisticsRef || !logisticsOp || !quantity) {
                alert(t('fill_all_fields'));
                return;
            }
            await props.onAddTask(
                logisticsRef,
                logisticsOp,
                quantity,
                'pallet',
                priority,
                true,
                logisticsPlate,
                false,
                sourceSector,
                targetSector
            );
            resetEntry();
        }
    };

    const counts = useMemo(() => ({
        tasks: props.tasks.filter(t => !t.isDone).length,
        pendingRequests: props.partRequests.length + props.bomRequests.length,
        erpBlockages: (props.erpBlockages || []).filter(b => b.status !== 'ready').length
    }), [props.tasks, props.partRequests, props.bomRequests, props.erpBlockages]);

    return (
        <div className="flex flex-col h-screen overflow-hidden bg-gray-900">
            {/* Top UI Bar */}
            <AppHeader 
                currentUser={props.currentUser}
                currentUserRole={props.currentUserRole}
                users={props.users}
                onLogout={props.onLogout}
                language={language as any}
                setLanguage={setLanguage as any}
                t={t}
                isFullscreen={isFullscreen}
                onToggleFullscreen={toggleFullscreen}
                installPrompt={props.installPrompt}
                onInstallApp={props.onInstallApp}
                hasPermission={hasPermission}
                resolveName={resolveName}
                isBreakActive={props.isBreakActive}
            />

            {/* Application Tab Selector */}
            <TabNavigator 
                activeTab={activeTab}
                setActiveTab={setActiveTab}
                hasPermission={hasPermission}
                t={t}
                counts={counts}
                currentUserRole={props.currentUserRole}
                systemConfig={props.systemConfig}
            />

            {/* Main Application Container */}
            <main className="flex-grow overflow-y-auto custom-scrollbar p-4 sm:p-6">
                <div className="max-w-7xl mx-auto h-full">
                    {activeTab === 'entry' && hasPermission('perm_tab_entry') && (
                        <ProductionEntry 
                            mode={mode}
                            setMode={setMode}
                            selectedPart={selectedPart}
                            setSelectedPart={setSelectedPart}
                            selectedWorkplace={selectedWorkplace}
                            setSelectedWorkplace={setSelectedWorkplace}
                            logisticsRef={logisticsRef}
                            setLogisticsRef={setLogisticsRef}
                            logisticsPlate={logisticsPlate}
                            setLogisticsPlate={setLogisticsPlate}
                            logisticsOp={logisticsOp}
                            setLogisticsOp={setLogisticsOp}
                            sourceSector={sourceSector}
                            setSourceSector={setSourceSector}
                            targetSector={targetSector}
                            setTargetSector={setTargetSector}
                            quantity={quantity}
                            setQuantity={setQuantity}
                            quantityUnit={quantityUnit}
                            setQuantityUnit={setQuantityUnit}
                            priority={priority}
                            setPriority={setPriority}
                            parts={props.parts}
                            workplaces={props.workplaces}
                            logisticsOperationsList={props.logisticsOperations}
                            mapSectors={props.mapSectors}
                            t={t}
                            language={language}
                            hasPermission={hasPermission}
                            handleAdd={handleAddTask}
                            onRequestPart={props.onRequestPart}
                        />
                    )}

                    {activeTab === 'tasks' && hasPermission('perm_tab_tasks') && (
                        <TaskList 
                            currentUser={props.currentUserRole as any}
                            currentUserName={props.currentUser}
                            tasks={props.tasks}
                            missingReasons={props.missingReasons}
                            mapSectors={props.mapSectors}
                            onToggleTask={props.onToggleTask}
                            onEditTask={props.onUpdateTask}
                            onDeleteTask={props.onDeleteTask}
                            onToggleMissing={props.onToggleMissing}
                            onSetInProgress={props.onSetInProgress}
                            onToggleBlock={props.onToggleBlock}
                            onToggleManualBlock={props.onToggleManualBlock}
                            onExhaustSearch={props.onExhaustSearch}
                            onMarkAsIncorrect={props.onMarkAsIncorrect}
                            onAddNote={props.onAddNote}
                            onReleaseTask={props.onReleaseTask}
                            onAuditPart={props.onStartAudit}
                            onFinishAudit={props.onFinishAudit}
                            hasPermission={hasPermission}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'bom' && hasPermission('perm_tab_bom') && (
                        <BOMScreen 
                            parts={props.parts}
                            workplaces={props.workplaces}
                            bomMap={props.bomMap}
                            onAddTask={props.onAddTask}
                            onRequestBOM={props.onRequestBOM}
                            t={t}
                            language={language}
                        />
                    )}

                    {activeTab === 'catalog' && hasPermission('perm_tab_catalog') && (
                        <PartCatalogTab 
                            parts={props.parts}
                            onSelectPart={(p) => { setSelectedPart(p.value); setActiveTab('entry'); }}
                        />
                    )}

                    {activeTab === 'missing' && hasPermission('perm_tab_missing') && (
                        <MissingItemsTab 
                            tasks={props.tasks}
                            onDeleteMissingItem={props.onDeleteMissingItem}
                            hasPermission={hasPermission}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'inventory' && hasPermission('perm_tab_inventory') && (
                        <InventoryTab 
                            currentUser={props.currentUser}
                            tasks={props.tasks}
                            onAddTask={props.onAddTask}
                            onUpdateTask={props.onUpdateTask}
                            onToggleTask={props.onToggleTask}
                            onDeleteTask={props.onDeleteTask}
                            hasPermission={hasPermission}
                            parts={props.parts.map(p => p.value)}
                            onRequestPart={props.onRequestPart}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'logistics' && hasPermission('perm_tab_logistics_center') && (
                        <LogisticsCenterTab 
                            tasks={props.tasks} 
                            draftTasks={props.draftTasks}
                            users={props.users}
                            fetchSanons={props.fetchSanons}
                            onDeleteTask={props.onDeleteTask} 
                            hasPermission={hasPermission} 
                            resolveName={resolveName} 
                        />
                    )}

                    {activeTab === 'map' && hasPermission('perm_tab_map') && (
                        <MapVisualizationTab 
                            tasks={props.tasks}
                            draftTasks={props.draftTasks}
                            fetchSanons={props.fetchSanons}
                            users={props.users}
                            mapSectors={props.mapSectors}
                            workplaces={props.workplaces}
                            logisticsOperations={props.logisticsOperations}
                            mapObstacles={props.mapObstacles}
                            systemConfig={props.systemConfig}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'logs' && hasPermission('perm_tab_logs') && (
                        <TransactionLogTab 
                            tasks={props.tasks}
                            draftTasks={props.draftTasks}
                            fetchSanons={props.fetchSanons}
                            users={props.users}
                            mapSectors={props.mapSectors}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'erp' && hasPermission('perm_tab_erp') && (
                        <ERPBlockageTab 
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            parts={props.parts}
                            blockages={props.erpBlockages}
                            resolveName={resolveName}
                            hasPermission={hasPermission}
                        />
                    )}

                    {activeTab === 'analytics' && hasPermission('perm_tab_analytics') && (
                        <AnalyticsTab 
                            systemConfig={props.systemConfig}
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            hasPermission={hasPermission}
                        />
                    )}

                    {activeTab === 'settings' && hasPermission('perm_tab_settings') && (
                        <SettingsTab 
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            installPrompt={props.installPrompt}
                            onInstallApp={props.onInstallApp}
                            systemConfig={props.systemConfig}
                            onUpdateSystemConfig={props.onUpdateSystemConfig}
                            onUpdateAdminKey={props.onUpdateAdminKey}
                            onToggleAdminLock={props.onToggleAdminLock}
                        />
                    )}

                    {activeTab === 'permissions' && hasPermission('perm_tab_permissions') && (
                        <PermissionsTab 
                            roles={props.roles}
                            onAddRole={props.onAddRole}
                            onDeleteRole={props.onDeleteRole}
                            onUpdatePermission={props.onUpdatePermission}
                            onVerifyAdminPassword={props.onVerifyAdminPassword}
                        />
                    )}
                </div>
            </main>
        </div>
    );
};

export default PartSearchScreen;

import React, { useState, useEffect, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { db } from '../../firebase';
import { doc, updateDoc, setDoc } from 'firebase/firestore';
import { ERPBlockage, DBItem } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';
import { useData } from '../../context/DataContext';
import PartNumberInput from '../PartNumberInput';

declare var XLSX: any;

interface ERPBlockageTabProps {
    currentUser: string;
    currentUserRole: string;
    parts: DBItem[];
    blockages: ERPBlockage[];
    resolveName: (username?: string | null) => string;
    hasPermission: (perm: string) => boolean;
}

const Icons = {
    Warning: () => <svg className="w-8 h-8 text-orange-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>,
    Check: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" /></svg>,
    Trash: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
    Excel: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
};

const ERPBlockageTab: React.FC<ERPBlockageTabProps> = ({ currentUser, currentUserRole, parts, blockages, resolveName, hasPermission }) => {
    const { t, language } = useLanguage();
    const { onAddNotification } = useData();

    // State
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [timer, setTimer] = useState(Date.now());

    // Form State
    const [partNumber, setPartNumber] = useState('');
    const [quantity, setQuantity] = useState('');
    const [userNote, setUserNote] = useState('');

    // Modal State
    const [finishModal, setFinishModal] = useState<{ isOpen: boolean; id: string | null; note: string }>({ isOpen: false, id: null, note: '' });
    const [confirmModal, setConfirmModal] = useState<{ isOpen: boolean; title: string; desc: string; onConfirm: () => void; type: 'danger' | 'warning' }>({ isOpen: false, title: '', desc: '', onConfirm: () => {}, type: 'danger' });

    useEffect(() => {
        const interval = setInterval(() => setTimer(Date.now()), 60000);
        return () => clearInterval(interval);
    }, []);

    const sortedList = useMemo(() => {
        const score = { waiting: 0, resolving: 1, ready: 2 };
        return [...blockages].sort((a, b) => {
            if (score[a.status] !== score[b.status]) return score[a.status] - score[b.status];
            return b.timestamp - a.timestamp;
        });
    }, [blockages]);

    // HANDLERS
    const handleAdd = async () => {
        if (!partNumber || !quantity || !userNote) {
            alert(t('fill_all_fields'));
            return;
        }
        setIsSubmitting(true);
        try {
            const newItem: ERPBlockage = {
                id: crypto.randomUUID(),
                partNumber,
                quantity,
                userNote,
                status: 'waiting',
                createdBy: currentUser,
                timestamp: Date.now()
            };
            const ref = doc(db, 'settings', 'erp_blockages');
            await setDoc(ref, { items: [newItem, ...blockages] }, { merge: true });

            // Vyčistenie formulára
            setPartNumber(''); setQuantity(''); setUserNote('');
        } catch (e) { console.error(e); }
        finally { setIsSubmitting(false); }
    };

    const updateStatus = async (id: string, updates: Partial<ERPBlockage>) => {
        try {
            const newList = blockages.map(item => item.id === id ? { ...item, ...updates } : item);
            await updateDoc(doc(db, 'settings', 'erp_blockages'), { items: newList });
        } catch (e) { console.error(e); }
    };

    const handleResolve = (id: string) => {
        updateStatus(id, { status: 'resolving', resolvedBy: currentUser });
    };

    const openFinishModal = (id: string) => {
        setFinishModal({ isOpen: true, id, note: '' });
    };

    const handleConfirmFinish = async () => {
        if (!finishModal.id || !finishModal.note.trim()) return;
        const item = blockages.find(b => b.id === finishModal.id);
        if (!item) return;

        const updates: Partial<ERPBlockage> = {
            status: 'ready',
            adminNote: finishModal.note,
            resolvedAt: Date.now(),
            resolvedBy: currentUser
        };

        await updateStatus(finishModal.id, updates);

        onAddNotification({
            partNumber: item.partNumber,
            reason: finishModal.note,
            reportedBy: currentUser,
            targetUser: item.createdBy,
            timestamp: Date.now()
        });

        setFinishModal({ isOpen: false, id: null, note: '' });
    };

    const handleDelete = (id: string) => {
        setConfirmModal({
            isOpen: true,
            title: t('erp_delete_confirm'),
            desc: language === 'sk' ? "Táto akcia je nevratná a záznam bude odstránený zo zoznamu." : "This action is irreversible.",
            type: 'danger',
            onConfirm: async () => {
                const newList = blockages.filter(b => b.id !== id);
                await updateDoc(doc(db, 'settings', 'erp_blockages'), { items: newList });
                setConfirmModal(p => ({ ...p, isOpen: false }));
            }
        });
    };

    const handleClearReady = () => {
        setConfirmModal({
            isOpen: true,
            title: t('erp_clear_confirm'),
            desc: language === 'sk' ? "Všetky záznamy v stave OPRAVENÉ budú natrvalo vymazané." : "All fixed records will be deleted.",
            type: 'danger',
            onConfirm: async () => {
                const newList = blockages.filter(b => b.status !== 'ready');
                await updateDoc(doc(db, 'settings', 'erp_blockages'), { items: newList });
                setConfirmModal(p => ({ ...p, isOpen: false }));
            }
        });
    };

    const handleExport = () => {
        if (typeof XLSX === 'undefined') return;
        const data = sortedList.map(b => ({
            "Dátum": new Date(b.timestamp).toLocaleDateString(),
            "Čas": new Date(b.timestamp).toLocaleTimeString(),
            "Diel": b.partNumber,
            "Množstvo": b.quantity,
            "Nahlásil": resolveName(b.createdBy),
            "Dôvod (User)": b.userNote,
            "Stav": b.status.toUpperCase(),
            "Riešiteľ": resolveName(b.resolvedBy),
            "Spätná väzba (Admin)": b.adminNote || ""
        }));
        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Chyby_Odvodu");
        XLSX.writeFile(wb, `Chyby_Odvodu_${new Date().toISOString().split('T')[0]}.xlsx`);
    };

    const getAgeingText = (ts: number) => {
        const diff = Math.floor((timer - ts) / 60000);
        return diff < 1 ? t('erp_ageing_now') : t('erp_ageing_min', { n: diff });
    };

    const canManage = hasPermission('perm_erp_manage');
    const canDelete = hasPermission('perm_erp_delete');

    return (
        <div className="max-w-7xl mx-auto space-y-8 pb-24 animate-fade-in text-slate-200">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div className="flex items-center gap-5">
                    <div className="p-4 bg-orange-500/20 rounded-2xl border border-orange-500/30">
                        <Icons.Warning />
                    </div>
                    <div>
                        <h2 className="text-3xl font-black text-white uppercase tracking-tighter leading-none">{t('erp_report_title')}</h2>
                        <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-2">{t('erp_report_subtitle')}</p>
                    </div>
                </div>
                <div className="flex gap-3 w-full md:w-auto">
                    <button onClick={handleExport} className="flex-1 md:flex-none h-12 px-6 bg-teal-600/10 hover:bg-teal-600/20 text-teal-500 border border-teal-500/30 rounded-xl font-black uppercase text-[10px] tracking-widest transition-all flex items-center justify-center gap-2">
                        <Icons.Excel /> {t('erp_btn_excel')}
                    </button>
                    {canDelete && (
                        <button onClick={handleClearReady} className="flex-1 md:flex-none h-12 px-6 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-500/30 rounded-xl font-black uppercase text-[10px] tracking-widest transition-all flex items-center justify-center gap-2">
                            <Icons.Trash /> {t('erp_btn_clear')}
                        </button>
                    )}
                </div>
            </div>

            <div className="bg-slate-900/60 border-2 border-slate-800 rounded-[2rem] p-8 shadow-2xl backdrop-blur-md relative overflow-hidden group">
                <div className="absolute top-0 right-0 w-64 h-64 bg-orange-500/5 rounded-full -mr-32 -mt-32 blur-[100px] pointer-events-none"></div>
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-end relative z-10">
                    <div className="space-y-4">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] ml-1">{t('part_number')}</label>
                            <PartNumberInput 
                                parts={parts.map(p => p.value)} 
                                value={partNumber} 
                                onPartSelect={(v) => setPartNumber(v || '')}
                                onInputChange={(v) => setPartNumber(v.toUpperCase())}
                                placeholder="33..."
                            />
                        </div>
