const TabNavigator: React.FC<TabNavigatorProps> = ({
  activeTab, setActiveTab, hasPermission, t, counts, currentUserRole, systemConfig
}) => {
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isStatsOpen, setIsStatsOpen] = useState(false);
  const [isLogisticsOpen, setIsLogisticsOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const adminDropdownRef = useRef<HTMLDivElement>(null);
  const statsDropdownRef = useRef<HTMLDivElement>(null);
  const logisticsDropdownRef = useRef<HTMLDivElement>(null);

  const currentOrder = systemConfig?.tabOrder || DEFAULT_TAB_ORDER;

  const ADMIN_TAB_IDS = ['settings', 'permissions'];
  const STAT_TAB_IDS = ['map', 'analytics', 'logs'];
  const LOG_TAB_IDS = ['logistics', 'catalog'];

  const isAdminTabActive = ADMIN_TAB_IDS.includes(activeTab);
  const isStatsTabActive = STAT_TAB_IDS.includes(activeTab);
  const isLogisticsTabActive = LOG_TAB_IDS.includes(activeTab);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as Node;
      if (adminDropdownRef.current && !adminDropdownRef.current.contains(target)) setIsAdminOpen(false);
      if (statsDropdownRef.current && !statsDropdownRef.current.contains(target)) setIsStatsOpen(false);
      if (logisticsDropdownRef.current && !logisticsDropdownRef.current.contains(target)) setIsLogisticsOpen(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const topLevelTabIds = currentOrder.filter(id => 
    !ADMIN_TAB_IDS.includes(id) && !STAT_TAB_IDS.includes(id) && !LOG_TAB_IDS.includes(id)
  );

  const allowedAdminTabs = TAB_CONFIG.filter(config => 
    ADMIN_TAB_IDS.includes(config.id) && (config.adminOnly ? currentUserRole === 'ADMIN' : true) && hasPermission(config.permission)
  );

  const allowedStatsTabs = TAB_CONFIG.filter(config => 
    STAT_TAB_IDS.includes(config.id) && (config.adminOnly ? currentUserRole === 'ADMIN' : true) && hasPermission(config.permission)
  );

  const allowedLogisticsTabs = TAB_CONFIG.filter(config => 
    LOG_TAB_IDS.includes(config.id) && (config.adminOnly ? currentUserRole === 'ADMIN' : true) && hasPermission(config.permission)
  );

  const renderDropdown = (labelKey: string, isOpen: boolean, setIsOpen: (val: boolean) => void, isActive: boolean, tabs: typeof TAB_CONFIG, dropdownRef: React.RefObject<HTMLDivElement | any>) => {
    if (tabs.length === 0) return null;
    return (
      <div className="relative ml-2 sm:ml-4 flex-shrink-0" ref={dropdownRef}>
        <button
          onClick={() => { if (!isOpen) { setIsAdminOpen(false); setIsStatsOpen(false); setIsLogisticsOpen(false); } setIsOpen(!isOpen); }}
          className={`flex items-center gap-1 sm:gap-2 py-3 px-2 sm:px-3 border-b-4 font-black text-sm transition-all ${isActive ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200'}`}
        >
          <span className="whitespace-nowrap uppercase tracking-tighter">{t(labelKey as any)}</span>
          <svg className={`w-4 h-4 transition-transform duration-200 ${isOpen ? 'rotate-180 text-teal-400' : 'text-gray-600'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 9l-7 7-7-7" /></svg>
          {(() => {
            const totalBadge = tabs.reduce((acc, curr) => acc + (curr.badgeKey ? counts[curr.badgeKey] : 0), 0);
            return totalBadge > 0 ? <span className="bg-red-500 text-white text-[9px] rounded-full w-4 h-4 flex items-center justify-center animate-bounce">!</span> : null;
          })()}
        </button>
        {isOpen && (
          <div className="absolute right-0 mt-1 w-56 bg-gray-900 border-2 border-slate-700 rounded-xl shadow-2xl overflow-hidden animate-fade-in z-[100]">
            <div className="py-2">
              {tabs.map(config => (
                  <button key={config.id} onClick={() => { setActiveTab(config.id); setIsOpen(false); }} className={`w-full flex items-center justify-between px-4 py-3 text-left text-sm font-bold transition-all ${activeTab === config.id ? 'bg-teal-600/20 text-teal-400' : 'text-gray-400 hover:bg-slate-800 hover:text-white'}`}>
                    <span className="uppercase tracking-wide">{t(config.labelKey as any)}</span>
                    {(config.badgeKey ? counts[config.badgeKey] : 0) > 0 && <span className={`text-[10px] text-white px-1.5 py-0.5 rounded-full ${config.id === 'settings' ? 'bg-red-500' : 'bg-orange-600'}`}>{(config.badgeKey ? counts[config.badgeKey] : 0)}</span>}
                  </button>
              ))}
            </div>
          </div>
        )}
      </div>
    );
  };

  return (
    <>
      {/* DESKTOP NAV (Hidden on Mobile) */}
      <div className="hidden md:block bg-gray-800 border-t border-gray-700 shadow-sm z-30">
        <div className="max-w-7xl mx-auto w-full px-4 flex items-center">
          <div className="flex space-x-6 overflow-x-auto custom-scrollbar flex-grow py-1">
            {topLevelTabIds.map(tabId => {
              const config = TAB_CONFIG.find(c => c.id === tabId);
              if (!config || (config.adminOnly && currentUserRole !== 'ADMIN') || !hasPermission(config.permission)) return null;
              return (
                <button key={config.id} onClick={() => { setActiveTab(config.id); setIsAdminOpen(false); setIsStatsOpen(false); setIsLogisticsOpen(false); }} className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === config.id ? (config.color || 'border-teal-500 text-teal-400') : `border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500`}`}>
                  {t(config.labelKey as any)}
                  {(config.badgeKey ? counts[config.badgeKey] : 0) > 0 && <span className={`ml-2 text-white text-[10px] rounded-full px-1.5 py-0.5 bg-orange-600`}>{(config.badgeKey ? counts[config.badgeKey] : 0)}</span>}
                </button>
              );
            })}
          </div>
          {renderDropdown('tab_logistics_group', isLogisticsOpen, setIsLogisticsOpen, isLogisticsTabActive, allowedLogisticsTabs, logisticsDropdownRef)}
          {renderDropdown('tab_statistics', isStatsOpen, setIsStatsOpen, isStatsTabActive, allowedStatsTabs, statsDropdownRef)}
          {renderDropdown('tab_administration', isAdminOpen, setIsAdminOpen, isAdminTabActive, allowedAdminTabs, adminDropdownRef)}
        </div>
      </div>

      {/* MOBILE BOTTOM NAV (Hidden on Desktop) */}
      <div className="md:hidden fixed bottom-0 left-0 right-0 bg-gray-900 border-t border-gray-800 z-[9998] flex items-center justify-around h-16 pb-safe px-2 shadow-[0_-4px_20px_rgba(0,0,0,0.5)]">
         <button onClick={() => setActiveTab('entry')} className={`flex flex-col items-center gap-1 ${activeTab === 'entry' ? 'text-teal-400' : 'text-gray-500'}`}>
            <Icons.Entry />
            <span className="text-[9px] font-black uppercase tracking-tighter">{t('tab_entry')}</span>
         </button>
         <button onClick={() => setActiveTab('tasks')} className={`relative flex flex-col items-center gap-1 ${activeTab === 'tasks' ? 'text-teal-400' : 'text-gray-500'}`}>
            <Icons.Tasks />
            <span className="text-[9px] font-black uppercase tracking-tighter">{t('tab_tasks')}</span>
            {counts.tasks > 0 && <span className="absolute -top-1 -right-1 bg-orange-600 text-white text-[8px] rounded-full w-4 h-4 flex items-center justify-center font-bold">{counts.tasks}</span>}
         </button>
         <button onClick={() => setActiveTab('missing')} className={`flex flex-col items-center gap-1 ${activeTab === 'missing' ? 'text-teal-400' : 'text-gray-500'}`}>
            <Icons.Missing />
            <span className="text-[9px] font-black uppercase tracking-tighter">{t('tab_missing')}</span>
         </button>
         <button onClick={() => setIsMobileMenuOpen(true)} className="flex flex-col items-center gap-1 text-gray-500">
            <Icons.More />
            <span className="text-[9px] font-black uppercase tracking-tighter">MENU</span>
         </button>
      </div>

      {/* MOBILE FULLSCREEN MENU DRAWER */}
      {isMobileMenuOpen && createPortal(
          <div className="fixed inset-0 z-[10001] bg-slate-950/95 backdrop-blur-xl animate-fade-in p-6 flex flex-col">
              <div className="flex justify-between items-center mb-8 border-b border-white/10 pb-4">
                  <h2 className="text-2xl font-black text-white uppercase tracking-tighter">DASHBOARD</h2>
                  <button onClick={() => setIsMobileMenuOpen(false)} className="p-2 text-slate-500 hover:text-white"><Icons.Close /></button>
              </div>

              <div className="flex-grow overflow-y-auto custom-scrollbar space-y-8">
                  {/* LOGISTIKA GROUP */}
                  {allowedLogisticsTabs.length > 0 && (
                      <div>
                          <div className="flex items-center gap-2 mb-4"><Icons.Logistics /><h3 className="text-xs font-black text-slate-500 uppercase tracking-widest">{t('tab_logistics_group')}</h3></div>
                          <div className="grid grid-cols-2 gap-3">
                              {allowedLogisticsTabs.map(tab => (
                                  <button key={tab.id} onClick={() => { setActiveTab(tab.id); setIsMobileMenuOpen(false); }} className={`p-4 rounded-2xl border-2 text-left transition-all ${activeTab === tab.id ? 'bg-teal-500/10 border-teal-500 text-teal-400 shadow-lg' : 'bg-slate-900 border-slate-800 text-slate-400'}`}>
                                      <p className="text-[10px] font-black uppercase tracking-widest leading-none">{t(tab.labelKey as any)}</p>
                                  </button>
                              ))}
                          </div>
                      </div>
                  )}

                  {/* STATS GROUP */}
                  {allowedStatsTabs.length > 0 && (
                      <div>
                          <div className="flex items-center gap-2 mb-4"><Icons.Analytics /><h3 className="text-xs font-black text-slate-500 uppercase tracking-widest">{t('tab_statistics')}</h3></div>
                          <div className="grid grid-cols-2 gap-3">
                              {allowedStatsTabs.map(tab => (
                                  <button key={tab.id} onClick={() => { setActiveTab(tab.id); setIsMobileMenuOpen(false); }} className={`p-4 rounded-2xl border-2 text-left transition-all ${activeTab === tab.id ? 'bg-sky-500/10 border-sky-500 text-sky-400 shadow-lg' : 'bg-slate-900 border-slate-800 text-slate-400'}`}>
                                      <p className="text-[10px] font-black uppercase tracking-widest leading-none">{t(tab.labelKey as any)}</p>
                                  </button>
                              ))}
                          </div>
                      </div>
                  )}

                  {/* ADMIN GROUP */}
                  {allowedAdminTabs.length > 0 && (
                      <div>
                          <div className="flex items-center gap-2 mb-4"><Icons.Settings /><h3 className="text-xs font-black text-slate-500 uppercase tracking-widest">{t('tab_administration')}</h3></div>
                          <div className="grid grid-cols-2 gap-3 pb-20">
                              {allowedAdminTabs.map(tab => (
                                  <button key={tab.id} onClick={() => { setActiveTab(tab.id); setIsMobileMenuOpen(false); }} className={`p-4 rounded-2xl border-2 text-left transition-all ${activeTab === tab.id ? 'bg-amber-500/10 border-amber-500 text-amber-500 shadow-lg' : 'bg-slate-900 border-slate-800 text-slate-400'}`}>
                                      <p className="text-[10px] font-black uppercase tracking-widest leading-none">{t(tab.labelKey as any)}</p>
                                  </button>
                              ))}
                          </div>
                      </div>
                  )}
              </div>
          </div>,
          document.body
      )}
    </>
  );
};

export default TabNavigator;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { useLanguage } from './LanguageContext';
import AppHeader from './AppHeader';
import TabNavigator from './TabNavigator';
import ProductionEntry from './tabs/ProductionEntry';
import TaskList from './tabs/TaskList';
import BOMScreen from './tabs/BOMScreen';
import MissingItemsTab from './tabs/MissingItemsTab';
import InventoryTab from './tabs/InventoryTab';
import LogisticsCenterTab from './tabs/LogisticsCenterTab';
import MapVisualizationTab from './tabs/MapVisualizationTab';
import TransactionLogTab from './tabs/TransactionLogTab';
import ERPBlockageTab from './tabs/ERPBlockageTab';
import AnalyticsTab from './tabs/Analytics/AnalyticsTab';
import SettingsTab from './settings/SettingsTab';
import PermissionsTab from './tabs/PermissionsTab';
import PartCatalogTab from './tabs/PartCatalogTab';
import { Task, PriorityLevel, DBItem, Role, SystemConfig, MapSector, MapObstacle, BOMComponent, PartRequest, BOMRequest, AdminNote, ERPBlockage } from '../types/appTypes';

// --- MAIN DASHBOARD COMPONENT ---
interface PartSearchScreenProps {
    tasks: Task[];
    draftTasks: Task[];
    users: any[];
    roles: Role[];
    workplaces: DBItem[];
    parts: { id: string; value: string; description?: string }[];
    missingReasons: DBItem[];
    logisticsOperations: DBItem[];
    mapSectors: MapSector[];
    mapObstacles: MapObstacle[];
    bomMap: Record<string, BOMComponent[]>;
    partRequests: PartRequest[];
    bomRequests: BOMRequest[];
    adminNotes: AdminNote[];
    erpBlockages: ERPBlockage[];
    systemConfig: SystemConfig;
    isBreakActive: boolean;

    currentUser: string;
    currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
    onLogout: () => void;

    // Task Actions
    onAddTask: (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, isLogistics?: boolean, noteOrPlate?: string, isProduction?: boolean, sourceSectorId?: string | null, targetSectorId?: string | null) => Promise<void>;
    onUpdateTask: (id: string, updates: Partial<Task>) => Promise<void>;
    onDeleteTask: (id: string) => Promise<void>;
    onToggleTask: (id: string, sectorId?: string) => Promise<void>;
    onSetInProgress: (id: string) => Promise<void>;
    onToggleBlock: (id: string) => Promise<void>;
    onToggleManualBlock: (id: string) => Promise<void>;
    onExhaustSearch: (id: string) => Promise<void>;
    onMarkAsIncorrect: (id: string) => Promise<void>;
    onAddNote: (id: string, note: string) => Promise<void>;
    onReleaseTask: (id: string) => Promise<void>;
    onStartAudit: (id: string) => Promise<void>;
    onFinishAudit: (id: string, result: 'found' | 'missing', note: string) => Promise<void>;
    onToggleMissing: (id: string, reason?: string) => Promise<void>;
    onDeleteMissingItem: (id: string) => Promise<void>;

    // User & Permission Management
    onUpdatePermission: (permissionName: string, roleName: string, hasPermission: boolean) => Promise<void>;
    onUpdateUserRole: (username: string, newRole: string) => Promise<void>;
    onAddRole: (name: string, parentId?: string, rank?: number) => Promise<void>;
    onDeleteRole: (id: string) => Promise<void>;

    // System Settings
    onUpdateSystemConfig: (config: Partial<SystemConfig>) => Promise<void>;
    onUpdateAdminKey: (oldKey: string, newKey: string) => Promise<void>;
    onToggleAdminLock: (val: boolean) => void;

    // Database Management
    onAddPart: (value: string, description?: string) => Promise<void>;
    onBatchAddParts: (vals: string[]) => Promise<void>;
    onDeletePart: (val: string) => Promise<void>;
    onDeleteAllParts: () => Promise<void>;

    onAddWorkplace: (val: string, time?: number, x?: number, y?: number) => Promise<void>;
    onUpdateWorkplace: (id: string, updates: Partial<DBItem>) => Promise<void>;
    onBatchAddWorkplaces: (vals: string[]) => Promise<void>;
    onDeleteWorkplace: (id: string) => Promise<void>;
    onDeleteAllWorkplaces: () => Promise<void>;

    onAddLogisticsOperation: (val: string, time?: number, dist?: number, x?: number, y?: number, defaultSource?: string, defaultTarget?: string) => Promise<void>;
    onUpdateLogisticsOperation: (id: string, updates: Partial<DBItem>) => Promise<void>;
    onDeleteLogisticsOperation: (id: string) => Promise<void>;
    onDeleteAllLogisticsOperations: () => Promise<void>;

    onAddMapSector: (name: string, x: number, y: number, color?: string) => Promise<void>;
    onUpdateMapSector: (id: string, updates: Partial<MapSector>) => Promise<void>;
    onDeleteMapSector: (id: string) => Promise<void>;

    onAddMapObstacle: (obs: Omit<MapObstacle, 'id'>) => Promise<void>;
    onDeleteMapObstacle: (id: string) => Promise<void>;

    onAddBOMItem: (parent: string, child: string, qty: number) => Promise<void>;
    onBatchAddBOMItems: (vals: string[]) => Promise<void>;
    onDeleteBOMItem: (parent: string, child: string) => Promise<void>;
    onDeleteAllBOMItems: () => Promise<void>;

    onAddMissingReason: (val: string) => Promise<void>;
    onDeleteMissingReason: (id: string) => Promise<void>;
    onAddBreakSchedule: (start: string, end: string) => Promise<void>;
    onDeleteBreakSchedule: (id: string) => Promise<void>;

    onAddAdminNote: (text: string, author: string) => Promise<void>;
    onDeleteAdminNote: (id: string) => Promise<void>;
    onClearAdminNotes: () => Promise<void>;

    // Maintenance & Data
    onDailyClosing: () => Promise<{ success: boolean; count: number }>;
    onWeeklyClosing: () => Promise<{ success: boolean; count: number; sanon: string }>;
    onPurgeOldTasks: () => Promise<number>;
    onExportTasksJSON: () => Promise<void>;
    onGetDocCount: () => Promise<number>;
    fetchSanons: () => Promise<any[]>;
    onRequestPart: (part: string) => Promise<boolean>;
    onRequestBOM: (parent: string) => Promise<boolean>;
    onVerifyAdminPassword: (password: string) => boolean;

    installPrompt: any;
    onInstallApp: () => void;
}

const PartSearchScreen: React.FC<PartSearchScreenProps> = (props) => {
    const { t, language, setLanguage } = useLanguage();
    const [activeTab, setActiveTab] = useState('entry');
    const [mode, setMode] = useState<'production' | 'logistics'>('production');
    const [isFullscreen, setIsFullscreen] = useState(false);

    // Form states for adding new tasks
    const [selectedPart, setSelectedPart] = useState<string | null>(null);
    const [selectedWorkplace, setSelectedWorkplace] = useState<string | null>(null);
    const [quantity, setQuantity] = useState('');
    const [quantityUnit, setQuantityUnit] = useState<'pcs' | 'boxes' | 'pallet'>('pcs');
    const [priority, setPriority] = useState<PriorityLevel>('NORMAL');
    const [logisticsRef, setLogisticsRef] = useState('');
    const [logisticsPlate, setLogisticsPlate] = useState('');
    const [logisticsOp, setLogisticsOp] = useState('');
    const [sourceSector, setSourceSector] = useState<string | null>(null);
    const [targetSector, setTargetSector] = useState<string | null>(null);

    // Fullscreen handling
    const toggleFullscreen = () => {
        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen().then(() => setIsFullscreen(true)).catch(err => console.error(err));
        } else {
            if (document.exitFullscreen) {
                document.exitFullscreen().then(() => setIsFullscreen(false)).catch(err => console.error(err));
            }
        }
    };

    // Permission check memoized for children
    const hasPermission = useCallback((permName: string) => {
        if (props.currentUserRole === 'ADMIN') return true;
        const roleObj = props.roles.find(r => r.name === props.currentUserRole);
        if (!roleObj) return false;
        return roleObj.permissions ? roleObj.permissions.includes(permName) : false;
    }, [props.roles, props.currentUserRole]);

    // Name resolution memoized for performance
    const resolveName = useCallback((username?: string | null) => {
        if (!username) return '-';
        const u = props.users.find(x => x.username === username);
        return (u?.nickname || username).toUpperCase();
    }, [props.users]);

    const resetEntry = () => {
        setSelectedPart(null);
        setSelectedWorkplace(null);
        setQuantity('');
        setQuantityUnit('pcs');
        setPriority('NORMAL');
        setLogisticsRef('');
        setLogisticsPlate('');
        setLogisticsOp('');
        setSourceSector(null);
        setTargetSector(null);
    };

    const handleAddTask = async () => {
        if (mode === 'production') {
            if (!selectedPart || !selectedWorkplace || !quantity) {
                alert(t('fill_all_fields'));
                return;
            }
            await props.onAddTask(
                selectedPart,
                selectedWorkplace,
                quantity,
                quantityUnit,
                priority,
                false,
                '',
                true
            );
            resetEntry();
        } else {
            if (!logisticsRef || !logisticsOp || !quantity) {
                alert(t('fill_all_fields'));
                return;
            }
            await props.onAddTask(
                logisticsRef,
                logisticsOp,
                quantity,
                'pallet',
                priority,
                true,
                logisticsPlate,
                false,
                sourceSector,
                targetSector
            );
            resetEntry();
        }
    };

    const counts = useMemo(() => ({
        tasks: props.tasks.filter(t => !t.isDone).length,
        pendingRequests: props.partRequests.length + props.bomRequests.length,
        erpBlockages: (props.erpBlockages || []).filter(b => b.status !== 'ready').length
    }), [props.tasks, props.partRequests, props.bomRequests, props.erpBlockages]);

    return (
        <div className="flex flex-col h-screen overflow-hidden bg-gray-900">
            {/* Top UI Bar */}
            <AppHeader 
                currentUser={props.currentUser}
                currentUserRole={props.currentUserRole}
                users={props.users}
                onLogout={props.onLogout}
                language={language as any}
                setLanguage={setLanguage as any}
                t={t}
                isFullscreen={isFullscreen}
                onToggleFullscreen={toggleFullscreen}
                installPrompt={props.installPrompt}
                onInstallApp={props.onInstallApp}
                hasPermission={hasPermission}
                resolveName={resolveName}
                isBreakActive={props.isBreakActive}
            />

            {/* Application Tab Selector */}
            <TabNavigator 
                activeTab={activeTab}
                setActiveTab={setActiveTab}
                hasPermission={hasPermission}
                t={t}
                counts={counts}
                currentUserRole={props.currentUserRole}
                systemConfig={props.systemConfig}
            />

            {/* Main Application Container - PB-20 added for mobile bottom bar */}
            <main className="flex-grow overflow-y-auto custom-scrollbar p-4 sm:p-6 pb-24 md:pb-6">
                <div className="max-w-7xl mx-auto h-full">
                    {activeTab === 'entry' && hasPermission('perm_tab_entry') && (
                        <ProductionEntry 
                            mode={mode}
                            setMode={setMode}
                            selectedPart={selectedPart}
                            setSelectedPart={setSelectedPart}
                            selectedWorkplace={selectedWorkplace}
                            setSelectedWorkplace={setSelectedWorkplace}
                            logisticsRef={logisticsRef}
                            setLogisticsRef={setLogisticsRef}
                            logisticsPlate={logisticsPlate}
                            setLogisticsPlate={setLogisticsPlate}
                            logisticsOp={logisticsOp}
                            setLogisticsOp={setLogisticsOp}
                            sourceSector={sourceSector}
                            setSourceSector={setSourceSector}
                            targetSector={targetSector}
                            setTargetSector={setTargetSector}
                            quantity={quantity}
                            setQuantity={setQuantity}
                            quantityUnit={quantityUnit}
                            setQuantityUnit={setQuantityUnit}
                            priority={priority}
                            setPriority={setPriority}
                            parts={props.parts}
                            workplaces={props.workplaces}
                            logisticsOperationsList={props.logisticsOperations}
                            mapSectors={props.mapSectors}
                            t={t}
                            language={language}
                            hasPermission={hasPermission}
                            handleAdd={handleAddTask}
                            onRequestPart={props.onRequestPart}
                        />
                    )}

                    {activeTab === 'tasks' && hasPermission('perm_tab_tasks') && (
                        <TaskList 
                            currentUser={props.currentUserRole as any}
                            currentUserName={props.currentUser}
                            tasks={props.tasks}
                            missingReasons={props.missingReasons}
                            mapSectors={props.mapSectors}
                            onToggleTask={props.onToggleTask}
                            onEditTask={props.onUpdateTask}
                            onDeleteTask={props.onDeleteTask}
                            onToggleMissing={props.onToggleMissing}
                            onSetInProgress={props.onSetInProgress}
                            onToggleBlock={props.onToggleBlock}
                            onToggleManualBlock={props.onToggleManualBlock}
                            onExhaustSearch={props.onExhaustSearch}
                            onMarkAsIncorrect={props.onMarkAsIncorrect}
                            onAddNote={props.onAddNote}
                            onReleaseTask={props.onReleaseTask}
                            onAuditPart={props.onStartAudit}
                            onFinishAudit={props.onFinishAudit}
                            hasPermission={hasPermission}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'bom' && hasPermission('perm_tab_bom') && (
                        <BOMScreen 
                            parts={props.parts}
                            workplaces={props.workplaces}
                            bomMap={props.bomMap}
                            onAddTask={props.onAddTask}
                            onRequestBOM={props.onRequestBOM}
                            t={t}
                            language={language}
                        />
                    )}

                    {activeTab === 'catalog' && hasPermission('perm_tab_catalog') && (
                        <PartCatalogTab 
                            parts={props.parts}
                            onSelectPart={(p) => { setSelectedPart(p.value); setActiveTab('entry'); }}
                        />
                    )}

                    {activeTab === 'missing' && hasPermission('perm_tab_missing') && (
                        <MissingItemsTab 
                            tasks={props.tasks}
                            onDeleteMissingItem={props.onDeleteMissingItem}
                            hasPermission={hasPermission}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'inventory' && hasPermission('perm_tab_inventory') && (
                        <InventoryTab 
                            currentUser={props.currentUser}
                            tasks={props.tasks}
                            onAddTask={props.onAddTask}
                            onUpdateTask={props.onUpdateTask}
                            onToggleTask={props.onToggleTask}
                            onDeleteTask={props.onDeleteTask}
                            hasPermission={hasPermission}
                            parts={props.parts.map(p => p.value)}
                            onRequestPart={props.onRequestPart}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'logistics' && hasPermission('perm_tab_logistics_center') && (
                        <LogisticsCenterTab 
                            tasks={props.tasks} 
                            draftTasks={props.draftTasks}
                            users={props.users}
                            fetchSanons={props.fetchSanons}
                            onDeleteTask={props.onDeleteTask} 
                            hasPermission={hasPermission} 
                            resolveName={resolveName} 
                        />
                    )}

                    {activeTab === 'map' && hasPermission('perm_tab_map') && (
                        <MapVisualizationTab 
                            tasks={props.tasks}
                            draftTasks={props.draftTasks}
                            fetchSanons={props.fetchSanons}
                            users={props.users}
                            mapSectors={props.mapSectors}
                            workplaces={props.workplaces}
                            logisticsOperations={props.logisticsOperations}
                            mapObstacles={props.mapObstacles}
                            systemConfig={props.systemConfig}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'logs' && hasPermission('perm_tab_logs') && (
                        <TransactionLogTab 
                            tasks={props.tasks}
                            draftTasks={props.draftTasks}
                            fetchSanons={props.fetchSanons}
                            users={props.users}
                            mapSectors={props.mapSectors}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'erp' && hasPermission('perm_tab_erp') && (
                        <ERPBlockageTab 
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            parts={props.parts}
                            blockages={props.erpBlockages}
                            resolveName={resolveName}
                            hasPermission={hasPermission}
                        />
                    )}

                    {activeTab === 'analytics' && hasPermission('perm_tab_analytics') && (
                        <AnalyticsTab 
                            systemConfig={props.systemConfig}
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            hasPermission={hasPermission}
                        />
                    )}

                    {activeTab === 'settings' && hasPermission('perm_tab_settings') && (
                        <SettingsTab 
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            installPrompt={props.installPrompt}
                            onInstallApp={props.onInstallApp}
                            systemConfig={props.systemConfig}
                            onUpdateSystemConfig={props.onUpdateSystemConfig}
                            onUpdateAdminKey={props.onUpdateAdminKey}
                            onToggleAdminLock={props.onToggleAdminLock}
                        />
                    )}

                    {activeTab === 'permissions' && hasPermission('perm_tab_permissions') && (
                        <PermissionsTab 
                            roles={props.roles}
                            onAddRole={props.onAddRole}
                            onDeleteRole={props.onDeleteRole}
                            onUpdatePermission={props.onUpdatePermission}
                            onVerifyAdminPassword={props.onVerifyAdminPassword}
                        />
                    )}
                </div>
            </main>
        </div>
    );
};

export default PartSearchScreen;

