    Missing: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>,
    More: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16m-7 6h7" /></svg>,
    Close: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>,
    Logistics: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16V6a1 1 0 00-1-1H4a1 1 0 00-1 1v10a1 1 0 001 1h1m8-1a1 1 0 01-1 1H9m4-1V8a1 1 0 011-1h2.586a1 1 0 01.707.293l3.414 3.414a1 1 0 01.293.707V16a1 1 0 01-1 1h-1m-6-1a1 1 0 001 1h1M5 17a2 2 0 104 0m-4 0a2 2 0 114 0m6 0a2 2 0 104 0m-4 0a2 2 0 114 0" /></svg>,
    Analytics: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>,
    Settings: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>,
    Inventory: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>,
    BOM: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" /></svg>,
    ERP: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>,
    Catalog: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5s3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>
};

const TabNavigator: React.FC<TabNavigatorProps> = ({
  activeTab, setActiveTab, hasPermission, t, counts, currentUserRole, systemConfig
}) => {
  const [openMenu, setOpenMenu] = useState<string | null>(null);
  const [dropdownPos, setDropdownPos] = useState({ top: 0, right: 0 });
  const [isMobileDrawerOpen, setIsMobileDrawerOpen] = useState(false);

  const navBarRef = useRef<HTMLDivElement>(null);
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  const currentOrder = systemConfig?.tabOrder || DEFAULT_TAB_ORDER;

  const ADMIN_TAB_IDS = ['settings', 'permissions'];
  const STAT_TAB_IDS = ['map', 'analytics', 'logs'];
  const LOG_TAB_IDS = ['logistics', 'catalog']; 
  const PARTS_TAB_IDS: string[] = []; // Všetko presunuté na hlavný panel

  const isAdminTabActive = ADMIN_TAB_IDS.includes(activeTab);
  const isStatsTabActive = STAT_TAB_IDS.includes(activeTab);
  const isLogisticsTabActive = LOG_TAB_IDS.includes(activeTab);

  // Zavrieť dropdown pri kliknutí mimo alebo pri scrollovaní lišty
  useEffect(() => {
    const handleGlobalClick = (e: MouseEvent) => {
        if (openMenu && !(e.target as HTMLElement).closest('.dropdown-trigger')) {
            setOpenMenu(null);
        }
    };
    const handleScroll = () => { if (openMenu) setOpenMenu(null); };

    document.addEventListener("mousedown", handleGlobalClick);
    const scrollContainer = scrollContainerRef.current;
    if (scrollContainer) scrollContainer.addEventListener('scroll', handleScroll);

    return () => {
        document.removeEventListener("mousedown", handleGlobalClick);
        if (scrollContainer) scrollContainer.removeEventListener('scroll', handleScroll);
    };
  }, [openMenu]);

  const topLevelTabIds = currentOrder.filter(id => 
    !ADMIN_TAB_IDS.includes(id) && !STAT_TAB_IDS.includes(id) && !LOG_TAB_IDS.includes(id) && !PARTS_TAB_IDS.includes(id)
  );

  const allowedAdminTabs = TAB_CONFIG.filter(config => 
    ADMIN_TAB_IDS.includes(config.id) && (config.adminOnly ? currentUserRole === 'ADMIN' : true) && hasPermission(config.permission)
  );

  const allowedStatsTabs = TAB_CONFIG.filter(config => 
    STAT_TAB_IDS.includes(config.id) && (config.adminOnly ? currentUserRole === 'ADMIN' : true) && hasPermission(config.permission)
  );

  const allowedLogisticsTabs = TAB_CONFIG.filter(config => 
    LOG_TAB_IDS.includes(config.id) && (config.adminOnly ? currentUserRole === 'ADMIN' : true) && hasPermission(config.permission)
  );

  const handleDropdownClick = (e: React.MouseEvent, menuId: string) => {
      if (openMenu === menuId) {
          setOpenMenu(null);
          return;
      }
      const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
      // Výpočet pozície pre Portál
      setDropdownPos({
          top: rect.bottom + window.scrollY,
          right: window.innerWidth - rect.right
      });
      setOpenMenu(menuId);
  };

  const renderDropdownTrigger = (labelKey: string, menuId: string, isActive: boolean, tabs: typeof TAB_CONFIG) => {
    if (tabs.length === 0) return null;
    return (
      <button
        onClick={(e) => handleDropdownClick(e, menuId)}
        className={`dropdown-trigger flex items-center gap-1 sm:gap-2 py-3 px-2 sm:px-3 border-b-4 font-black text-sm transition-all flex-shrink-0 ${isActive ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200'}`}
      >
        <span className="whitespace-nowrap uppercase tracking-tighter">{t(labelKey as any)}</span>
        <svg className={`w-4 h-4 transition-transform duration-200 ${openMenu === menuId ? 'rotate-180 text-teal-400' : 'text-gray-600'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 9l-7 7-7-7" /></svg>
        {(() => {
          const totalBadge = tabs.reduce((acc, curr) => acc + (curr.badgeKey ? (counts as any)[curr.badgeKey] : 0), 0);
          return totalBadge > 0 ? <span className="bg-orange-600 text-white text-[9px] rounded-full w-4 h-4 flex items-center justify-center font-bold">!</span> : null;
        })()}
      </button>
    );
  };

  const renderPortalMenu = (menuId: string, tabs: typeof TAB_CONFIG) => {
      if (openMenu !== menuId) return null;
      return createPortal(
          <div 
            style={{ 
                position: 'fixed', 
                top: `${dropdownPos.top + 4}px`, 
                right: `${dropdownPos.right}px`,
                zIndex: 9999 
            }}
            className="w-56 bg-gray-900 border-2 border-slate-700 rounded-xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] overflow-hidden animate-fade-in"
          >
              <div className="py-2">
                {tabs.map(config => (
                    <button 
                        key={config.id} 
                        onClick={() => { setActiveTab(config.id); setOpenMenu(null); }} 
                        className={`w-full flex items-center justify-between px-4 py-3 text-left text-sm font-bold transition-all ${activeTab === config.id ? 'bg-teal-600/20 text-teal-400' : 'text-gray-400 hover:bg-slate-800 hover:text-white'}`}
                    >
                        <span className="uppercase tracking-wide">{t(config.labelKey as any)}</span>
                        {(config.badgeKey ? (counts as any)[config.badgeKey] : 0) > 0 && <span className={`text-[10px] text-white px-1.5 py-0.5 rounded-full ${config.id === 'settings' ? 'bg-red-500' : 'bg-orange-600'}`}>{(counts as any)[config.badgeKey]}</span>}
                    </button>
                ))}
              </div>
          </div>,
          document.body
      );
  };

  return (
    <>
      {/* RESPONSIVE HORIZONTAL SCROLL NAV PANEL */}
      <div className="bg-gray-800 border-t border-gray-700 shadow-sm z-30 sticky top-0" ref={navBarRef}>
        <div 
            ref={scrollContainerRef}
            className="max-w-7xl mx-auto w-full px-4 flex items-center overflow-x-auto no-scrollbar custom-scrollbar"
        >
          <div className="flex flex-nowrap items-center min-w-full">
            <div className="flex space-x-4 sm:space-x-6 py-1">
              {topLevelTabIds.map(tabId => {
                const config = TAB_CONFIG.find(c => c.id === tabId);
                if (!config || (config.adminOnly && currentUserRole !== 'ADMIN') || !hasPermission(config.permission)) return null;
                return (
                  <button 
                    key={config.id} 
                    onClick={() => { setActiveTab(config.id); setOpenMenu(null); }} 
                    className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === config.id ? (config.color || 'border-teal-500 text-teal-400') : `border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500`}`}
                  >
                    {t(config.labelKey as any)}
                    {(config.badgeKey ? (counts as any)[config.badgeKey] : 0) > 0 && <span className={`ml-2 text-white text-[10px] rounded-full px-1.5 py-0.5 bg-orange-600`}>{(counts as any)[config.badgeKey]}</span>}
                  </button>
                );
              })}
            </div>

            {/* GROUPED DROPDOWNS ALIGNED TO THE RIGHT */}
            <div className="ml-auto flex items-center">
                {renderDropdownTrigger('tab_logistics_group', 'logistics', isLogisticsTabActive, allowedLogisticsTabs)}
                {renderDropdownTrigger('tab_statistics', 'stats', isStatsTabActive, allowedStatsTabs)}
                {renderDropdownTrigger('tab_administration', 'admin', isAdminTabActive, allowedAdminTabs)}
            </div>
          </div>
        </div>
      </div>

      {/* PORTAL RENDERED MENUS */}
      {renderPortalMenu('logistics', allowedLogisticsTabs)}
      {renderPortalMenu('stats', allowedStatsTabs)}
      {renderPortalMenu('admin', allowedAdminTabs)}

      {/* MOBILE BOTTOM NAV */}
      <div className="md:hidden fixed bottom-0 left-0 right-0 h-20 bg-slate-900 border-t border-slate-800 z-[9998] flex items-center justify-around px-4 pb-safe shadow-[0_-10px_30px_rgba(0,0,0,0.5)]">
          <button 
            onClick={() => setActiveTab('entry')} 
            className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'entry' ? 'text-teal-400 scale-110' : 'text-slate-500'}`}
          >
            <Icons.Entry />
            <span className="text-[9px] font-black uppercase tracking-tighter">{t('tab_entry')}</span>
          </button>

          <button 
            onClick={() => setActiveTab('tasks')} 
            className={`relative flex flex-col items-center gap-1 transition-all ${activeTab === 'tasks' ? 'text-teal-400 scale-110' : 'text-slate-500'}`}
          >
            <Icons.Tasks />
            <span className="text-[9px] font-black uppercase tracking-tighter">{t('tab_tasks')}</span>
            {counts.tasks > 0 && (
              <span className="absolute -top-1 -right-1 bg-orange-600 text-white text-[8px] font-black rounded-full w-4 h-4 flex items-center justify-center animate-bounce">
                {counts.tasks}
              </span>
            )}
          </button>

          <button 
            onClick={() => setActiveTab('missing')} 
            className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'missing' ? 'text-teal-400 scale-110' : 'text-slate-500'}`}
          >
            <Icons.Missing />
            <span className="text-[9px] font-black uppercase tracking-tighter">{t('tab_missing')}</span>
          </button>

          <button 
            onClick={() => setIsMobileDrawerOpen(true)} 
            className="flex flex-col items-center gap-1 text-amber-500 hover:text-white transition-all"
          >
            <Icons.More />
            <span className="text-[9px] font-black uppercase tracking-tighter">MENU</span>
          </button>
      </div>

      {/* MOBILE DRAWER PORTAL */}
      {isMobileDrawerOpen && createPortal(
          <div className="fixed inset-0 z-[10001] bg-black/80 backdrop-blur-md animate-fade-in flex flex-col justify-end" onClick={() => setIsMobileDrawerOpen(false)}>
              <div 
                className="bg-slate-900 w-full rounded-t-[2.5rem] border-t-2 border-slate-700 p-8 max-h-[90vh] overflow-y-auto custom-scrollbar shadow-2xl"
                onClick={e => e.stopPropagation()}
              >
                  <div className="flex justify-between items-center mb-8 border-b border-white/5 pb-6">
                      <h2 className="text-2xl font-black text-white uppercase tracking-tighter">SYSTÉMOVÉ MENU</h2>
                      <button onClick={() => setIsMobileDrawerOpen(false)} className="p-3 bg-slate-800 rounded-2xl text-slate-400"><Icons.Close /></button>
                  </div>

                  <div className="space-y-10">
                      {/* LOGISTIKA & KATALÓG */}
                      {allowedLogisticsTabs.length > 0 && (
                          <div>
                              <div className="flex items-center gap-3 mb-4 text-sky-500">
                                  <Icons.Logistics />
                                  <h3 className="text-xs font-black uppercase tracking-[0.2em]">{t('tab_logistics_group')}</h3>
                              </div>
                              <div className="grid grid-cols-2 gap-3">
                                  {allowedLogisticsTabs.map(tab => (
                                      <button key={tab.id} onClick={() => { setActiveTab(tab.id); setIsMobileDrawerOpen(false); }} className={`flex flex-col justify-between p-4 h-24 rounded-2xl border-2 transition-all text-left ${activeTab === tab.id ? 'bg-sky-500/10 border-sky-500 text-sky-400' : 'bg-slate-800/50 border-slate-800 text-slate-500'}`}>
                                          <div className="flex justify-between">
                                            {tab.id === 'catalog' ? <Icons.Catalog /> : <Icons.Logistics />}
                                            {(tab.badgeKey ? (counts as any)[tab.badgeKey] : 0) > 0 && <span className="bg-orange-600 text-white text-[8px] font-black px-1.5 py-0.5 rounded-md">{(counts as any)[tab.badgeKey]}</span>}
                                          </div>
                                          <span className="text-[10px] font-black uppercase tracking-widest leading-none">{t(tab.labelKey as any)}</span>
                                      </button>
                                  ))}
                              </div>
                          </div>
                      )}

                      {/* HLAVNÉ NÁSTROJE (BOM, INVENTÚRA, ERP) */}
                      <div>
                          <div className="flex items-center gap-3 mb-4 text-teal-400">
                              <Icons.Inventory />
                              <h3 className="text-xs font-black uppercase tracking-[0.2em]">HLAVNÉ NÁSTROJE</h3>
                          </div>
                          <div className="grid grid-cols-2 gap-3">
                              {['bom', 'inventory', 'erp'].map(id => {
                                  const tab = TAB_CONFIG.find(c => c.id === id);
                                  if (!tab || !hasPermission(tab.permission)) return null;
                                  return (
                                      <button key={tab.id} onClick={() => { setActiveTab(tab.id); setIsMobileDrawerOpen(false); }} className={`flex flex-col justify-between p-4 h-24 rounded-2xl border-2 transition-all text-left ${activeTab === tab.id ? 'bg-teal-500/10 border-teal-500 text-teal-400' : 'bg-slate-800/50 border-slate-800 text-slate-500'}`}>
                                          <div className="flex justify-between">
                                            {tab.id === 'bom' ? <Icons.BOM /> : tab.id === 'erp' ? <Icons.ERP /> : <Icons.Inventory />}
                                            {(tab.badgeKey ? (counts as any)[tab.badgeKey] : 0) > 0 && <span className="bg-orange-600 text-white text-[8px] font-black px-1.5 py-0.5 rounded-md">{(counts as any)[tab.badgeKey]}</span>}
                                          </div>
                                          <span className="text-[10px] font-black uppercase tracking-widest leading-none">{t(tab.labelKey as any)}</span>
                                      </button>
                                  );
                              })}
                          </div>
                      </div>

                      {/* ŠTATISTIKY */}
                      {allowedStatsTabs.length > 0 && (
                          <div>
                              <div className="flex items-center gap-3 mb-4 text-indigo-500">
                                  <Icons.Analytics />
                                  <h3 className="text-xs font-black uppercase tracking-[0.2em]">{t('tab_statistics')}</h3>
                              </div>
                              <div className="grid grid-cols-2 gap-3">
                                  {allowedStatsTabs.map(tab => (
                                      <button key={tab.id} onClick={() => { setActiveTab(tab.id); setIsMobileDrawerOpen(false); }} className={`flex flex-col justify-between p-4 h-24 rounded-2xl border-2 transition-all text-left ${activeTab === tab.id ? 'bg-indigo-500/10 border-indigo-500 text-indigo-400' : 'bg-slate-800/50 border-slate-800 text-slate-500'}`}>
                                          <Icons.Analytics />
                                          <span className="text-[10px] font-black uppercase tracking-widest leading-none">{t(tab.labelKey as any)}</span>
                                      </button>
                                  ))}
                              </div>
                          </div>
                      )}

                      {/* ADMINISTRÁCIA */}
                      {allowedAdminTabs.length > 0 && (
                          <div className="pb-8">
                              <div className="flex items-center gap-3 mb-4 text-amber-500">
                                  <Icons.Settings />
                                  <h3 className="text-xs font-black uppercase tracking-[0.2em]">{t('tab_administration')}</h3>
                              </div>
                              <div className="grid grid-cols-2 gap-3">
                                  {allowedAdminTabs.map(tab => (
                                      <button key={tab.id} onClick={() => { setActiveTab(tab.id); setIsMobileDrawerOpen(false); }} className={`flex flex-col justify-between p-4 h-24 rounded-2xl border-2 transition-all text-left ${activeTab === tab.id ? 'bg-amber-500/10 border-amber-500 text-amber-500' : 'bg-slate-800/50 border-slate-800 text-slate-500'}`}>
                                          <div className="flex justify-between">
                                            <Icons.Settings />
